function docIsExpired(doc) {
  if (!doc.expires || !doc.uploaded_at) return false;
  const uploaded = new Date(doc.uploaded_at);
  const now = new Date();
  const diffDays = (now - uploaded) / (1000 * 60 * 60 * 24);
  return diffDays > 365;
}

