// ─── GOOGLE MAPS LIVE ─────────────────────────────────────────────────────────
const GMAPS_KEY = "AIzaSyDLgkdqtb72-UyeZPEA_2dL2ijYIsjRUHU";
let gmapsPromise = null;
function loadGoogleMaps() {
  if (gmapsPromise) return gmapsPromise;
  if (window.google?.maps) { gmapsPromise = Promise.resolve(); return gmapsPromise; }
  gmapsPromise = new Promise((resolve, reject) => {
    window.__gmapsReady = resolve;
    const s = document.createElement("script");
    s.src = `https://maps.googleapis.com/maps/api/js?key=${GMAPS_KEY}&libraries=places,geometry&callback=__gmapsReady&loading=async`;
    s.async = true;
    s.onerror = (e) => { console.error("Google Maps load error:", e); reject(e); };
    document.head.appendChild(s);
  });
  return gmapsPromise;
}

function MapView({ height, riderMode, driverLat, driverLng, riderLat, riderLng, finding, driverVehicle, destLat, destLng, mode }) {
  const ref = useRef(null);
  const mapRef = useRef(null);
  const driverMarkerRef = useRef(null);
  const riderMarkerRef  = useRef(null);
  const myLocMarkerRef  = useRef(null);
  const destMarkerRef   = useRef(null);
  const routeRendererRef = useRef(null);
  const directionsServiceRef = useRef(null);
  const [ready, setReady] = useState(!!window.google?.maps);
  const [myLat, setMyLat] = useState(null);
  const [myLng, setMyLng] = useState(null);

  // Get device GPS first — map will centre here
  useEffect(() => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition(
      pos => { setMyLat(pos.coords.latitude); setMyLng(pos.coords.longitude); },
      () => { setMyLat(43.2557); setMyLng(-79.8711); }, // fallback Hamilton
      { enableHighAccuracy: true, timeout: 8000 }
    );
  }, []);

  useEffect(() => {
    loadGoogleMaps()
      .then(() => setReady(true))
      .catch(e => console.error("Maps failed:", e));
  }, []);

  // Best center: driver GPS > rider GPS > device GPS > Hamilton default
  const centerLat = driverLat || riderLat || myLat || 43.2557;
  const centerLng = driverLng || riderLng || myLng || -79.8711;

  useEffect(() => {
    if (!ready || !ref.current) return;
    // Wait until we have a real location before initialising
    if (!myLat && !driverLat && !riderLat) return;
    if (!mapRef.current) {
      mapRef.current = new window.google.maps.Map(ref.current, {
        center: { lat: centerLat, lng: centerLng },
        zoom: 16,
        disableDefaultUI: true,
        zoomControl: true,
        styles: []
      });
    } else {
      // Pan to best available position
      mapRef.current.panTo({ lat: centerLat, lng: centerLng });
    }

    // Rider = 🙋 emoji, Driver = car emoji matching vehicle
    if (myLat && myLng) {
      const mpos = { lat: myLat, lng: myLng };
      const myEmoji = riderMode ? "🙋" : "🚗";
      const mySize  = riderMode ? 44 : 40;
      const myIconSvg = `<svg xmlns='http://www.w3.org/2000/svg' width='${mySize}' height='${mySize}' viewBox='0 0 ${mySize} ${mySize}'><text y='${mySize-4}' font-size='${mySize-4}'>${myEmoji}</text></svg>`;
      const myIcon = {
        url: "data:image/svg+xml;charset=UTF-8," + encodeURIComponent(myIconSvg),
        scaledSize: new window.google.maps.Size(mySize, mySize),
        anchor: new window.google.maps.Point(mySize/2, mySize),
      };
      if (!myLocMarkerRef.current) {
        myLocMarkerRef.current = new window.google.maps.Marker({
          map: mapRef.current, position: mpos, icon: myIcon,
          title: riderMode ? "You" : "You", zIndex: 10
        });
      } else {
        myLocMarkerRef.current.setPosition(mpos);
        myLocMarkerRef.current.setIcon(myIcon);
      }
    }

    // Driver marker — emoji based on vehicle type
    if (driverLat && driverLng) {
      const pos = { lat: driverLat, lng: driverLng };
      // Pick emoji based on vehicle name keywords
      const veh = (driverVehicle||"").toLowerCase();
      const carEmoji = veh.includes("suv")||veh.includes("van")||veh.includes("sienna")||
        veh.includes("odyssey")||veh.includes("pilot")||veh.includes("traverse")||
        veh.includes("suburban")||veh.includes("expedition")||veh.includes("tahoe") ? "🚐"
        : veh.includes("truck")||veh.includes("ram")||veh.includes("f-150")||
          veh.includes("tacoma")||veh.includes("sierra") ? "🛻"
        : "🚗";
      const carSize = carEmoji === "🚐" ? 48 : 40;
      const carSvg = `<svg xmlns='http://www.w3.org/2000/svg' width='${carSize}' height='${carSize}' viewBox='0 0 ${carSize} ${carSize}'><text y='${carSize-4}' font-size='${carSize-6}'>${carEmoji}</text></svg>`;
      const driverIcon = {
        url: "data:image/svg+xml;charset=UTF-8," + encodeURIComponent(carSvg),
        scaledSize: new window.google.maps.Size(carSize, carSize),
        anchor: new window.google.maps.Point(carSize/2, carSize),
      };
      if (!driverMarkerRef.current) {
        driverMarkerRef.current = new window.google.maps.Marker({
          map: mapRef.current, position: pos, icon: driverIcon, title: "Driver", zIndex: 20
        });
      } else {
        driverMarkerRef.current.setPosition(pos);
        driverMarkerRef.current.setIcon(driverIcon);
      }
      mapRef.current.panTo(pos);
    }

    // Rider marker (person pin)
    if (riderLat && riderLng) {
      const rpos = { lat: riderLat, lng: riderLng };
      if (!riderMarkerRef.current) {
        riderMarkerRef.current = new window.google.maps.Marker({
          map: mapRef.current,
          position: rpos,
          icon: {
            url: "data:image/svg+xml;charset=UTF-8," + encodeURIComponent('<svg xmlns="http://www.w3.org/2000/svg" width="36" height="36" viewBox="0 0 36 36"><circle cx="18" cy="18" r="16" fill="#2563eb" stroke="#fff" stroke-width="3"/><text x="18" y="24" text-anchor="middle" font-size="18">📍</text></svg>'),
            scaledSize: new window.google.maps.Size(36, 36),
            anchor: new window.google.maps.Point(18, 18),
          },
          title: "Pickup"
        });
      } else {
        riderMarkerRef.current.setPosition(rpos);
      }
    }

    // ── Route & Bounds logic based on mode ───────────────────────────────
    if (!directionsServiceRef.current && window.google?.maps) {
      directionsServiceRef.current = new window.google.maps.DirectionsService();
    }
    if (!routeRendererRef.current && window.google?.maps) {
      routeRendererRef.current = new window.google.maps.DirectionsRenderer({
        suppressMarkers: true,
        polylineOptions: { strokeColor:"#2563eb", strokeWeight:5, strokeOpacity:0.85 }
      });
      routeRendererRef.current.setMap(mapRef.current);
    }

    function fitAll(...points) {
      const valid = points.filter(p => p && p.lat && p.lng);
      if (valid.length < 2) return;
      const bounds = new window.google.maps.LatLngBounds();
      valid.forEach(p => bounds.extend({ lat: p.lat, lng: p.lng }));
      mapRef.current.fitBounds(bounds, { top:80, bottom:100, left:60, right:60 });
    }

    function drawRoute(origin, dest, color="#2563eb") {
      if (!origin?.lat || !dest?.lat || !directionsServiceRef.current) return;
      if (routeRendererRef.current) {
        routeRendererRef.current.setOptions({
          polylineOptions: { strokeColor: color, strokeWeight:5, strokeOpacity:0.85 }
        });
      }
      directionsServiceRef.current.route({
        origin: { lat: origin.lat, lng: origin.lng },
        destination: { lat: dest.lat, lng: dest.lng },
        travelMode: window.google.maps.TravelMode.DRIVING
      }, (result, status) => {
        if (status === "OK" && routeRendererRef.current) {
          routeRendererRef.current.setDirections(result);
        }
      });
    }

    function clearRoute() {
      if (routeRendererRef.current) routeRendererRef.current.setDirections({ routes:[] });
      if (destMarkerRef.current) { destMarkerRef.current.setMap(null); destMarkerRef.current = null; }
    }

    function placeDestMarker(pos) {
      const flagSvg = "<svg xmlns='http://www.w3.org/2000/svg' width='44' height='48' viewBox='0 0 44 48'><text y='40' font-size='36'>🏁</text></svg>";
      if (!destMarkerRef.current) {
        destMarkerRef.current = new window.google.maps.Marker({
          map: mapRef.current, position: pos, zIndex:15,
          icon: { url:"data:image/svg+xml;charset=UTF-8,"+encodeURIComponent(flagSvg),
            scaledSize:new window.google.maps.Size(44,48), anchor:new window.google.maps.Point(10,48) },
          title:"Destination"
        });
      } else { destMarkerRef.current.setPosition(pos); }
    }

    // MODE: rider browsing — show route rider→dest, fit both in view
    if ((mode==="rider-browse" || (!mode && riderMode)) && destLat && destLng && riderLat && riderLng) {
      placeDestMarker({ lat:destLat, lng:destLng });
      drawRoute({ lat:riderLat, lng:riderLng }, { lat:destLat, lng:destLng });
      fitAll({ lat:riderLat, lng:riderLng }, { lat:destLat, lng:destLng });
    }

    // MODE: rider enroute — driver coming to pickup — fit driver+rider in view
    else if (mode==="rider-pickup" && driverLat && driverLng && riderLat && riderLng) {
      drawRoute({ lat:driverLat, lng:driverLng }, { lat:riderLat, lng:riderLng }, "#f59e0b");
      fitAll({ lat:driverLat, lng:driverLng }, { lat:riderLat, lng:riderLng });
    }

    // MODE: rider in trip — driver heading to destination — fit driver+dest
    else if (mode==="rider-trip" && driverLat && driverLng && destLat && destLng) {
      placeDestMarker({ lat:destLat, lng:destLng });
      drawRoute({ lat:driverLat, lng:driverLng }, { lat:destLat, lng:destLng });
      fitAll({ lat:driverLat, lng:driverLng }, { lat:destLat, lng:destLng });
    }

    // MODE: driver pickup — navigate from driver to rider — fit both + turn-by-turn
    else if (mode==="driver-pickup" && driverLat && driverLng && riderLat && riderLng) {
      drawRoute({ lat:driverLat, lng:driverLng }, { lat:riderLat, lng:riderLng }, "#f59e0b");
      fitAll({ lat:driverLat, lng:driverLng }, { lat:riderLat, lng:riderLng });
    }

    // MODE: driver trip — navigate driver to destination — follow driver, show route
    else if (mode==="driver-trip" && driverLat && driverLng && destLat && destLng) {
      placeDestMarker({ lat:destLat, lng:destLng });
      drawRoute({ lat:driverLat, lng:driverLng }, { lat:destLat, lng:destLng });
      // Keep driver centered with heading tilt for navigation feel
      if (mapRef.current) {
        mapRef.current.panTo({ lat:driverLat, lng:driverLng });
        mapRef.current.setZoom(17);
        mapRef.current.setTilt(45);
      }
    }

    // No route needed — clear
    else if (!destLat && !destLng) {
      clearRoute();
    }

  }, [ready, mode, myLat, myLng, driverLat, driverLng, riderLat, riderLng, destLat, destLng, driverVehicle]);

  if (!ready) return (
    <div style={{ width:"100%", height: height||200, borderRadius:14, background:"#1e293b",
      display:"flex", alignItems:"center", justifyContent:"center" }}>
      <div style={{ color:"#60a5fa", fontSize:12 }}>Loading map…</div>
    </div>
  );

  return (
    <div style={{ width:"100%", height: height||200, borderRadius:14, overflow:"hidden",
      border:"1px solid "+BORDER, position:"relative" }}>
      <div ref={ref} style={{ width:"100%", height:"100%" }} />
    </div>
  );
}



