// ─── WEEKLY EARNINGS TAB ─────────────────────────────────────────────────────
function WeeklyEarningsTab({ trips, earned }) {
  const DAYS = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  const now  = new Date();

  // Build 7-day data (last 7 days)
  const days = Array.from({length:7},(_,i)=>{
    const d = new Date(now);
    d.setDate(d.getDate() - (6-i));
    const label = DAYS[d.getDay()];
    const dateStr = d.toLocaleDateString("en-CA");
    const dayTrips = trips.filter(t => t.date === dateStr);
    const amt = dayTrips.reduce((s,t)=>s+parseFloat((t.fare||"0").replace("CA$","")),0);
    return { label, dateStr, amt, count: dayTrips.length };
  });

  const maxAmt = Math.max(...days.map(d=>d.amt), 1);
  const weekTotal = days.reduce((s,d)=>s+d.amt, 0);
  const weekTrips = days.reduce((s,d)=>s+d.count, 0);
  const avgFare   = weekTrips ? weekTotal/weekTrips : 0;
  const today     = now.toLocaleDateString("en-CA");

  return (
    <div className="fade" style={{ paddingBottom:80 }}>
      {/* Header */}
      <div style={{ background:"linear-gradient(160deg,"+NAVY+","+DARK+")", padding:"20px 20px 24px" }}>
        <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:900, fontSize:20, color:WHITE }}>💰 Weekly Earnings</div>
        <div style={{ color:LBLUE, fontSize:12, marginTop:2 }}>Last 7 days</div>
        <div style={{ marginTop:14, display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8 }}>
          {[["Total","CA$"+weekTotal.toFixed(2),"💵"],["Trips",weekTrips,"🚗"],["Avg Fare",weekTrips?"CA$"+avgFare.toFixed(2):"—","📊"]].map(([lb,val,ic])=>(
            <div key={lb} style={{ background:"rgba(255,255,255,0.08)", borderRadius:12, padding:"10px 6px", textAlign:"center" }}>
              <div style={{ fontSize:16 }}>{ic}</div>
              <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:14, color:WHITE, marginTop:4 }}>{String(val)}</div>
              <div style={{ fontSize:10, color:LBLUE, marginTop:2 }}>{lb}</div>
            </div>
          ))}
        </div>
      </div>

      <div style={{ padding:"16px 16px 0" }}>
        {/* Bar chart */}
        <div style={{ background:"#eff6ff", borderRadius:16, padding:"16px", marginBottom:14, border:"1px solid "+BORDER }}>
          <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:13, color:NAVY, marginBottom:14 }}>Daily Income</div>
          <div style={{ display:"flex", alignItems:"flex-end", justifyContent:"space-between", gap:6, height:140 }}>
            {days.map((d,i)=>{
              const barH = d.amt > 0 ? Math.max(18, Math.round((d.amt/maxAmt)*110)) : 4;
              const isToday = d.dateStr === today;
              return (
                <div key={i} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:4 }}>
                  {/* Amount label above bar */}
                  <div style={{ fontSize:9, fontWeight:700, color:d.amt>0?BLUE:SLATE, whiteSpace:"nowrap" }}>
                    {d.amt>0?"CA$"+d.amt.toFixed(0):""}
                  </div>
                  {/* Bar */}
                  <div style={{ width:"100%", height:barH, borderRadius:"6px 6px 3px 3px", background:isToday?"linear-gradient(180deg,#3b82f6,#1d4ed8)":d.amt>0?"linear-gradient(180deg,#60a5fa,#3b82f6)":"#e2e8f0", boxShadow:d.amt>0?"0 2px 8px rgba(59,130,246,0.3)":"none", transition:"height 0.4s ease" }} />
                  {/* Day label */}
                  <div style={{ fontSize:10, fontWeight:isToday?800:500, color:isToday?BLUE:SLATE }}>{d.label}</div>
                </div>
              );
            })}
          </div>
          <div style={{ display:"flex", gap:14, marginTop:10 }}>
            <div style={{ display:"flex", alignItems:"center", gap:5 }}>
              <div style={{ width:10, height:10, borderRadius:3, background:"#3b82f6" }} />
              <span style={{ fontSize:10, color:SLATE }}>This week</span>
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:5 }}>
              <div style={{ width:10, height:10, borderRadius:3, background:"#1d4ed8" }} />
              <span style={{ fontSize:10, color:SLATE }}>Today</span>
            </div>
          </div>
        </div>

        {/* Cash out card */}
        <div style={{ background:"linear-gradient(135deg,#1e3a5f,#1d4ed8)", borderRadius:14, padding:"14px 16px", marginBottom:14, display:"flex", justifyContent:"space-between", alignItems:"center", boxShadow:"0 4px 14px rgba(37,99,235,0.3)" }}>
          <div>
            <div style={{ color:"rgba(255,255,255,0.7)", fontSize:10, fontWeight:600 }}>Available to Cash Out</div>
            <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:900, fontSize:24, color:WHITE }}>{"CA$"+weekTotal.toFixed(2)}</div>
          </div>
          <button style={{ background:WHITE, border:"none", borderRadius:10, padding:"9px 16px", color:"#2563eb", fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:13, cursor:weekTotal>0?"pointer":"not-allowed", opacity:weekTotal>0?1:0.5, boxShadow:"0 2px 8px rgba(0,0,0,0.12)" }}>
            Cash Out
          </button>
        </div>

        {/* Trip history */}
        <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:13, color:NAVY, marginBottom:10 }}>Trip History — This Week</div>
        {trips.length===0 ? (
          <div style={{ textAlign:"center", paddingTop:30, color:SLATE, paddingBottom:20 }}>
            <div style={{ fontSize:36, marginBottom:10 }}>📭</div>
            <div style={{ fontWeight:600 }}>No trips this week</div>
            <div style={{ fontSize:12, marginTop:4 }}>Complete trips to see them here</div>
          </div>
        ) : (
          trips.map((t,i)=>(
            <div key={i} style={{ background:"#eff6ff", borderRadius:12, padding:"12px 14px", marginBottom:8, border:"1px solid "+BORDER, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div>
                <div style={{ fontWeight:700, fontSize:13, color:NAVY }}>{t.dest}</div>
                <div style={{ fontSize:11, color:SLATE, marginTop:2 }}>{t.type} · {t.date}</div>
              </div>
              <div style={{ fontWeight:800, color:GREEN, fontSize:14 }}>{t.fare}</div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

// ─── MONTHLY SUMMARY TAB ─────────────────────────────────────────────────────
function MonthlySummaryTab({ trips, earned, displayName }) {
  const now   = new Date();
  const MONTHS = ["January","February","March","April","May","June","July","August","September","October","November","December"];
  const [selMonth, setSelMonth] = useState(now.getMonth());
  const [selYear,  setSelYear]  = useState(now.getFullYear());
  const COMMISSION_RATE = getLive("commPct", 20) / 100; // reads from admin settings

  // Build per-month trip data
  function tripsForMonth(m, y) {
    return trips.filter(t => {
      const d = new Date(t.date);
      return d.getMonth() === m && d.getFullYear() === y;
    });
  }

  const monthTrips   = tripsForMonth(selMonth, selYear);
  const grossEarned  = monthTrips.reduce((s, t) => s + parseFloat(t.fare.replace("CA$","")||0), 0);
  const commission   = grossEarned * COMMISSION_RATE;
  const subFee       = getLive("subFee", 25); // reads from admin settings
  const netPayout    = Math.max(0, grossEarned - commission - subFee);
  const avgFare      = monthTrips.length ? grossEarned / monthTrips.length : 0;

  // Month picker — prev/next
  function prevMonth() {
    if (selMonth === 0) { setSelMonth(11); setSelYear(y => y - 1); }
    else setSelMonth(m => m - 1);
  }
  function nextMonth() {
    const isCurrentMonth = selMonth === now.getMonth() && selYear === now.getFullYear();
    if (isCurrentMonth) return;
    if (selMonth === 11) { setSelMonth(0); setSelYear(y => y + 1); }
    else setSelMonth(m => m + 1);
  }
  const isCurrentMonth = selMonth === now.getMonth() && selYear === now.getFullYear();

  return (
    <div className="fade" style={{ paddingBottom:80 }}>
      {/* Header */}
      <div style={{ background:"linear-gradient(160deg,"+NAVY+","+DARK+")", padding:"20px 20px 24px" }}>
        <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:900, fontSize:18, color:WHITE, marginBottom:2 }}>📊 Monthly Summary</div>
        <div style={{ color:LBLUE, fontSize:12 }}>End-of-month payment report</div>
        {/* Month navigator */}
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:16, background:"rgba(255,255,255,0.07)", borderRadius:12, padding:"10px 14px" }}>
          <button onClick={prevMonth} style={{ background:"rgba(255,255,255,0.1)", border:"none", borderRadius:8, width:32, height:32, color:WHITE, fontSize:18, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>‹</button>
          <div style={{ textAlign:"center" }}>
            <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:18, color:WHITE }}>{MONTHS[selMonth]}</div>
            <div style={{ color:LBLUE, fontSize:12 }}>{selYear}</div>
          </div>
          <button onClick={nextMonth} style={{ background: isCurrentMonth?"rgba(255,255,255,0.05)":"rgba(255,255,255,0.1)", border:"none", borderRadius:8, width:32, height:32, color: isCurrentMonth?"#475569":WHITE, fontSize:18, cursor: isCurrentMonth?"not-allowed":"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>›</button>
        </div>
      </div>

      <div style={{ padding:"16px 16px 0" }}>
        {/* Summary card */}
        <div style={{ background:"linear-gradient(135deg,#1e3a5f,#1d4ed8)", borderRadius:16, padding:"18px", marginBottom:14, boxShadow:"0 4px 20px rgba(37,99,235,0.25)" }}>
          <div style={{ color:"rgba(255,255,255,0.7)", fontSize:10, fontWeight:700, letterSpacing:1, textTransform:"uppercase" }}>Net Payout — {MONTHS[selMonth]} {selYear}</div>
          <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:900, fontSize:44, color:WHITE, marginTop:4 }}>{"CA$"+netPayout.toFixed(2)}</div>
          <div style={{ color:"rgba(255,255,255,0.6)", fontSize:11, marginTop:4 }}>After platform fee &amp; subscription</div>
          <button style={{ marginTop:14, background:WHITE, border:"none", borderRadius:10, padding:"10px 22px", color:"#2563eb", fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:13, cursor: netPayout > 0 ? "pointer" : "not-allowed", opacity: netPayout > 0 ? 1 : 0.5, boxShadow:"0 2px 8px rgba(0,0,0,0.15)" }}>
            {netPayout > 0 ? "Cash Out CA$"+netPayout.toFixed(2) : "Nothing to cash out"}
          </button>
        </div>

        {/* Breakdown */}
        <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:13, color:NAVY, marginBottom:10, letterSpacing:0.5 }}>Earnings Breakdown</div>
        <Card style={{ marginBottom:14, padding:0, overflow:"hidden" }}>
          {[
            ["Gross Earnings",   "CA$"+grossEarned.toFixed(2),  GREEN,  "💰"],
            ["Platform Fee (20%)","- CA$"+commission.toFixed(2), "#ef4444", "⚙️"],
            ["Weekly Sub × 4",   "- CA$"+subFee.toFixed(2),     "#f59e0b", "💳"],
            ["Net Payout",        "CA$"+netPayout.toFixed(2),    GREEN,  "✅"],
          ].map(([label, val, color, ic], i, arr) => (
            <div key={label} style={{ padding:"13px 16px", borderBottom: i<arr.length-1?"1px solid "+BORDER:"none", display:"flex", alignItems:"center", gap:12, background: i===arr.length-1?"#eff6ff":"transparent" }}>
              <span style={{ fontSize:18 }}>{ic}</span>
              <span style={{ flex:1, fontSize:13, fontWeight: i===arr.length-1?700:500, color:NAVY }}>{label}</span>
              <span style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:14, color }}>{val}</span>
            </div>
          ))}
        </Card>

        {/* Stats row */}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:10, marginBottom:14 }}>
          {[["🚗","Trips",monthTrips.length],["💵","Avg Fare",monthTrips.length?"CA$"+avgFare.toFixed(2):"-"],["⭐","Rating",(calcRating(trips)??"5.0")+""]].map(([ic,lb,val])=>(
            <Card key={lb} style={{ textAlign:"center", padding:"12px 8px" }}>
              <div style={{ fontSize:20 }}>{ic}</div>
              <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:15, color:NAVY, marginTop:4 }}>{String(val)}</div>
              <div style={{ fontSize:10, color:"rgba(255,255,255,0.85)", marginTop:2 }}>{lb}</div>
            </Card>
          ))}
        </div>

        {/* Trip list for month */}
        <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:13, color:NAVY, marginBottom:10 }}>Trip History — {MONTHS[selMonth]}</div>
        {monthTrips.length === 0 ? (
          <div style={{ textAlign:"center", paddingTop:30, color:SLATE, paddingBottom:20 }}>
            <div style={{ fontSize:36, marginBottom:10 }}>📭</div>
            <div style={{ fontWeight:600 }}>No trips this month</div>
            <div style={{ fontSize:12, marginTop:4 }}>Complete trips to see them here</div>
          </div>
        ) : (
          monthTrips.map((t,i) => (
            <Card key={i} style={{ marginBottom:10, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div>
                <div style={{ fontWeight:700, fontSize:13, color:NAVY }}>{t.dest}</div>
                <div style={{ fontSize:11, color:SLATE, marginTop:2 }}>{t.type} · {t.date}</div>
              </div>
              <div style={{ fontWeight:800, color:GREEN, fontSize:14 }}>{t.fare}</div>
            </Card>
          ))
        )}
      </div>
    </div>
  );
}

