                  {vehicles.length>1&&<button onClick={()=>removeVehicle(v.id)} style={{ fontSize:14, background:"#fef2f2", border:"none", borderRadius:8, padding:"5px 8px", cursor:"pointer", color:"#ef4444" }}>✕</button>}
